// 取得全域暫存的時間記錄
let lastTrigger = context.get('lastTrigger') || null;
let lastTime = context.get('lastTime') || 0;
let now = Date.now();

// 設定感應間隔（例如 3 秒內連續觸發才算一組動作）
let timeout = 3000;

if (lastTrigger === null || (now - lastTime) > timeout) {
    // 這是第一顆感測器被觸發，記錄下來
    context.set('lastTrigger', msg.topic);
    context.set('lastTime', now);
    return null; // 還沒完成判斷，不輸出
} else {
    // 這是短時間內的第二顆感測器觸發
    if (lastTrigger === "outside" && msg.topic === "inside") {
        msg.payload = "Customer Entered (客人進店)";
    } else if (lastTrigger === "inside" && msg.topic === "outside") {
        msg.payload = "Customer Left (客人離開)";
    }

    // 重置記錄，準備下一次判斷
    context.set('lastTrigger', null);
    return msg;
}

// 1. 取得當前的距離數值
let distance = Number(msg.payload);

// 2. 判斷現在「有沒有傘」 (小於 5 公分代表有傘)
let hasUmbrella = (distance < 5);

// 3. 取得「前一次」的狀態
let lastState = context.get('lastState') || false;
context.set('lastState', hasUmbrella);

// 4. 判斷邏輯並賦予專屬 Topic
if (hasUmbrella === true && lastState === false) {
    // 狀況 A：剛放入雨傘
    msg.topic = "umbrella/slot1/insert";  // 告訴電腦這是 Slot 1 放入
    msg.payload = "Take Photo";
    return msg; 

} else if (hasUmbrella === false && lastState === true) {
    // 狀況 B：剛拿走雨傘
    msg.topic = "umbrella/slot1/remove";  // 告訴電腦這是 Slot 1 拿走
    msg.payload = "Take Photo";
    return msg; 

} else {
    // 狀況 C：狀態沒變，不拍照
    return null;
}

let distance = Number(msg.payload);
let hasUmbrella = (distance < 5);

// Node-RED 的 context 記憶是每個節點獨立的，所以不會和 Slot 1 打架
let lastState = context.get('lastState') || false;
context.set('lastState', hasUmbrella);

if (hasUmbrella === true && lastState === false) {
    msg.topic = "umbrella/slot2/insert";  // 改為 slot2
    msg.payload = "Take Photo";
    return msg; 
} else if (hasUmbrella === false && lastState === true) {
    msg.topic = "umbrella/slot2/remove";  // 改為 slot2
    msg.payload = "Take Photo";
    return msg; 
} else {
    return null;
}

if (msg.payload === "ON") {
    // msg.payload = true; // 觸發蜂鳴器
    // return msg;
    msg.payload = {
        "warning": true,
        "line1": "Warning!!",  // 螢幕要顯示的文字
        "line2": "Theft detected!!!",
        "color": "red"
    };
    return msg;
}
return null;

// 1. 設定你的 API Key (從 Azure Portal 的 "Manage keys" 取得)
const apiKey = "YOUR_AZURE_OPENAI_API_KEY";

// 2. 準備 HTTP Header
msg.headers = {
    "api-key": apiKey,
    "Content-Type": "application/json"
};

// 3. 處理圖片：將相機輸出的 Buffer 轉為 Base64
// 假設前方相機節點輸出在 msg.payload
let base64Image = "";
if (Buffer.isBuffer(msg.payload)) {
    base64Image = msg.payload.toString('base64');
} else {
    node.error("找不到有效的圖片資料，請確認相機節點輸出格式為 Buffer");
    return null;
}

// 4. 組合成 Azure OpenAI 要求的 JSON 格式
msg.payload = {
    "messages": [
        {
            "role": "system",
            "content": "Your are eyes of a smart umbrella rack."
        },
        {
            "role": "user",
            "content": [
                {
                    "type": "text",
                    "text": "This image shows the area in front of an umbrella rack. Please briefly describe what you see. If there is a person in the image, do they appear nervous? Do they exhibit any suspicious behavior similar to a thief?"
                },
                {
                    "type": "image_url",
                    "image_url": {
                        "url": "data:image/jpeg;base64," + base64Image
                    }
                }
            ]
        }
    ],
    "max_tokens": 500,
    "temperature": 0.5
};

return msg;

// 確保傳入的是物件格式
let data = msg.payload;

// 如果資料還是 JSON 字串，先轉換它
if (typeof data === "string") {
    try {
        data = JSON.parse(data);
    } catch (e) {
        node.error("無法解析 JSON 資料");
    }
}

// 提取 AI 的回答文字 (這是關鍵路徑)
if (data && data.choices && data.choices[0] && data.choices[0].message) {
    let aiResponse = data.choices[0].message.content;

    // 將結果加上 Markdown 標籤後傳出
    msg.payload = aiResponse;
    return msg;
}

node.error("API 回傳格式不符合預期");
return null;

// 1. 取得相機原始資料並轉為 Base64
const base64Data = msg.payload.toString('base64');
const base64Full = "data:image/jpeg;base64," + base64Data;

// 2. 輸出 1：直接給 Dashboard 顯示 (拍完立刻觸發)
let msgToUI = {
    payload: base64Full
};

return msgToUI;

// 取得 API 回傳的數據
const weather = msg.payload;

// 整理成 InfluxDB 寫入格式：[ {資料欄位}, {標籤} ]
msg.payload = [
    {
        temp: weather.main.temp,        // 溫度
        humidity: weather.main.humidity, // 濕度
        pressure: weather.main.pressure, // 氣壓
        wind_speed: weather.wind.speed,   // 風速
        sunrise: weather.sys.sunrise, // 日出時間 (Unix)
        sunset: weather.sys.sunset    // 日落時間 (Unix)
    },
    {
        location: weather.name,          // 城市名稱作為標籤
        zip: flow.get("zip")             // 郵遞區號作為標籤
    }
];

// 設定 InfluxDB 的測量名稱 (Measurement)
msg.measurement = "weather_info";

return msg;

/*
  Function: Sensor Display Formatter
  -----------------------------------
  This function reads light, rotary (pressure), and ultrasonic (distance)
  values from msg.payload, formats them for display (line1 and line2),
  and assigns a color indicator based on the pressure value.
*/
const light = Number(msg.payload.light);
const pressure = Number(msg.payload.rotary);
const distance = Number(msg.payload.ultrasonic);

// Format LCD / Dashboard lines
msg.line1 = `Light: ${light}`;
msg.line2 = `Pr: ${pressure}`;
msg.line2 = msg.line2 + ` Dst: ${distance}`;

// Assign status color based on pressure thresholds
// Green  -> High pressure (>700)
// Yellow -> Medium pressure (>300)
// Red    -> Low pressure (<=300)
if (pressure > 700) msg.color = "green";
else if (pressure > 300) msg.color = "yellow";
else msg.color = "red";

return msg;

msg.payload = {
    "line1": "Remember to take",  // 螢幕要顯示的文字
    "line2": "your umbrella!",
    "color": "yellow"
};
return msg;

// 檢查前一個節點傳來的 payload 裡是否有 warning
if (msg.payload && msg.payload.warning === true) {
    // 💡 因為是單色 LED，我們直接送出 1 代表「開」
    msg.payload = 1; 
} else {
    // 送出 0 代表「關」
    msg.payload = 0;
}

// 傳送整個 msg 物件給 LED 節點
return msg;
